const fs = require('fs');
const content = fs.readFileSync('C:/Users/yyzypublic/.openclaw/workspace/devops_page.html', 'utf8');

// 提取文本内容，去掉 HTML 标签
const text = content.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ');

// 搜索 1v1 / 1V1 相关内容
const idx = text.toLowerCase().indexOf('1v1');
if (idx !== -1) {
  console.log('找到 1v1，上下文：');
  console.log(text.substring(Math.max(0, idx-200), idx+500));
} else {
  console.log('未找到 1v1');
}

// 搜索 pipeline 相关
const pipelineMatches = [];
const re = /pipeline|流水线/gi;
let m;
let count = 0;
while ((m = re.exec(text)) !== null && count < 5) {
  pipelineMatches.push(text.substring(Math.max(0, m.index-50), m.index+100));
  count++;
}
console.log('Pipeline matches:', pipelineMatches.join('\n---\n'));
"

