const { chromium } = require('playwright');
const fs = require('fs');

(async () => {
  const cookiesRaw = fs.readFileSync('C:/Users/yyzypublic/.openclaw/workspace/devops_cookies.json', 'utf8');
  const cookies = JSON.parse(cookiesRaw);

  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext();
  await context.addCookies(cookies);

  const page = await context.newPage();
  await page.goto('https://devops.devcloud.ztgame.com/projects/yyzy/pipelines', { waitUntil: 'networkidle', timeout: 30000 });

  console.log('URL after load:', page.url());

  // 等待流水线列表出现
  await page.waitForSelector('.pipeline-name, [class*="pipeline"], .name', { timeout: 15000 }).catch(() => console.log('selector not found, continuing'));

  // 找 1v1 标签并点击
  const allText = await page.evaluate(() => document.body.innerText);
  console.log('Page text (first 2000):', allText.substring(0, 2000));

  // 查找 1v1 按钮
  const buttons = await page.evaluate(() => {
    const els = Array.from(document.querySelectorAll('*'));
    return els
      .filter(el => el.childElementCount === 0 && el.textContent.trim() === '1v1')
      .map(el => ({ tag: el.tagName, class: el.className, text: el.textContent.trim() }));
  });
  console.log('1v1 elements:', JSON.stringify(buttons));

  await browser.close();
})().catch(e => { console.error('Error:', e.message); process.exit(1); });

