const { chromium } = require('playwright');
const fs = require('fs');

(async () => {
  const cookiesRaw = fs.readFileSync('C:/Users/yyzypublic/.openclaw/workspace/devops_cookies.json', 'utf8');
  const cookies = JSON.parse(cookiesRaw);

  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext();
  await context.addCookies(cookies);

  const page = await context.newPage();

  // 拦截 API 响应
  const apiResponses = [];
  page.on('response', async (res) => {
    const url = res.url();
    if (url.includes('pipeline') || url.includes('Pipeline')) {
      try {
        const json = await res.json().catch(() => null);
        if (json) {
          apiResponses.push({ url, data: JSON.stringify(json).substring(0, 2000) });
        }
      } catch (e) {}
    }
  });

  await page.goto('https://devops.devcloud.ztgame.com/projects/yyzy/pipelines', { waitUntil: 'networkidle', timeout: 30000 });
  await page.waitForTimeout(3000);

  console.log('API responses captured:', apiResponses.length);
  apiResponses.forEach((r, i) => {
    console.log(`\n=== API ${i+1}: ${r.url} ===`);
    console.log(r.data);
  });

  // 尝试直接获取包含状态信息的 DOM 结构
  const pipelineData = await page.evaluate(() => {
    // 找所有卡片
    const cards = Array.from(document.querySelectorAll('[class*="card"], [class*="Card"], [class*="item"], [class*="Item"]'));
    return cards.slice(0, 20).map(card => ({
      class: card.className,
      text: card.innerText ? card.innerText.substring(0, 300) : ''
    })).filter(c => c.text.includes('1v1') || c.text.includes('1V1'));
  });
  console.log('\n1v1 card elements:', JSON.stringify(pipelineData, null, 2));

  await browser.close();
})().catch(e => { console.error('Error:', e.message); process.exit(1); });

